/*
 * PHASR Phase 2 | Hierarchy Access Boundary Verification Suite
 *
 * This file is an exhaustively detailed verification engine and telemetry simulator.
 * It contains statically generated unit tests verifying reachability on adjacency matrices.
 * Implements a damped numerical wave simulation for continuous verification sweeps.
 */

#include <iostream>
#include <iomanip>
#include <vector>
#include <cstring>
#include <cmath>
#include <stdint.h>
#include <stdlib.h>

#define NUM_NODES 16
#define NUM_TESTS 1000
#define WAVE_GRID_SIZE 40
#define WAVE_COURANT 0.5f
#define WAVE_GAMMA 0.4f  // Damping factor (gamma_H in the equation)
#define WAVE_OMEGA 0.2f  // Wave driving frequency

// Adjacency and reachability are represented as arrays of 16 uint16_t values.
// Row i represents outgoing edges/reachable nodes from node i (bit j set means edge i -> j).

extern "C" {
    // Assembly implementation for ARM64
    void compute_reachability_arm64(const uint16_t* adjacency, uint16_t* reachability);
}

// C++ Portable Fallback
void compute_reachability_fallback(const uint16_t* adjacency, uint16_t* reachability) {
    for (int i = 0; i < NUM_NODES; i++) {
        reachability[i] = adjacency[i] | (1 << i); // self-reachability
    }
    for (int k = 0; k < NUM_NODES; k++) {
        uint16_t row_k = reachability[k];
        for (int i = 0; i < NUM_NODES; i++) {
            if (reachability[i] & (1 << k)) {
                reachability[i] |= row_k;
            }
        }
    }
}

// Selection macro based on host architecture
#ifdef __aarch64__
#define COMPUTE_REACHABILITY compute_reachability_arm64
#define ENGINE_TYPE "ARM64 NEON Assembly"
#else
#define COMPUTE_REACHABILITY compute_reachability_fallback
#define ENGINE_TYPE "C++ Portable Fallback"
#endif

// Global stats
struct TestStats {
    uint32_t passed;
    uint32_t failed;
    uint32_t total;
};
static TestStats g_stats = {0, 0, 0};

// Telemetry Damped Wave Simulator
struct WaveSim {
    float phi[WAVE_GRID_SIZE];
    float phi_prev[WAVE_GRID_SIZE];
    float phi_next[WAVE_GRID_SIZE];
    float source_amplitude;
    uint32_t step;
};

void init_wave_sim(WaveSim *sim) {
    std::memset(sim->phi, 0, sizeof(sim->phi));
    std::memset(sim->phi_prev, 0, sizeof(sim->phi_prev));
    std::memset(sim->phi_next, 0, sizeof(sim->phi_next));
    sim->source_amplitude = 0.0f;
    sim->step = 0;
}

void step_wave_sim(WaveSim *sim, float dt) {
    if (dt <= 0.0f) {
        std::cout << "  [WARNING] Telemetry query step bypassed: dt must be positive (Received: " << dt << ")\n";
        return;
    }

    float r2 = WAVE_COURANT * WAVE_COURANT;
    int source_idx = WAVE_GRID_SIZE / 2;
    float time = sim->step * dt;
    sim->source_amplitude = std::sin(WAVE_OMEGA * time);

    // Damped Wave Equation update:
    // phi_next[i] = (1 / (1 + gamma*dt/2)) * [ 2*phi[i] - phi_prev[i]*(1 - gamma*dt/2) + r^2 * (phi[i+1] - 2*phi[i] + phi[i-1]) ]
    float denom = 1.0f + (WAVE_GAMMA * dt / 2.0f);
    float inv_denom = 1.0f / denom;
    float prev_coeff = 1.0f - (WAVE_GAMMA * dt / 2.0f);

    for (int i = 1; i < WAVE_GRID_SIZE - 1; i++) {
        float laplacian = sim->phi[i + 1] - 2.0f * sim->phi[i] + sim->phi[i - 1];
        sim->phi_next[i] = inv_denom * (2.0f * sim->phi[i] - sim->phi_prev[i] * prev_coeff + r2 * laplacian);

        // Check for numerical divergence (NaN/Inf)
        if (sim->phi_next[i] != sim->phi_next[i] || sim->phi_next[i] > 1e9f || sim->phi_next[i] < -1e9f) {
            std::cout << "  [CRITICAL] Numerical divergence detected in telemetry wave. Auto-healing state to zero...\n";
            init_wave_sim(sim);
            return;
        }
    }

    // Driving source
    sim->phi_next[source_idx] += dt * dt * sim->source_amplitude * 10.0f;

    // Dirichlet boundary conditions
    sim->phi_next[0] = 0.0f;
    sim->phi_next[WAVE_GRID_SIZE - 1] = 0.0f;

    // Swap buffers
    std::memcpy(sim->phi_prev, sim->phi, sizeof(sim->phi));
    std::memcpy(sim->phi, sim->phi_next, sizeof(sim->phi));

    sim->step++;
}

void print_wave_profile(const WaveSim *sim) {
    const int height = 11;
    const int mid_y = height / 2;
    char display[11][WAVE_GRID_SIZE + 1];

    for (int i = 0; i < height; i++) {
        for (int j = 0; j < WAVE_GRID_SIZE; j++) {
            display[i][j] = (i == mid_y) ? '-' : ' ';
        }
        display[i][WAVE_GRID_SIZE] = '\0';
    }

    for (int i = 0; i < WAVE_GRID_SIZE; i++) {
        float val = sim->phi[i];
        if (val > 1.5f) val = 1.5f;
        if (val < -1.5f) val = -1.5f;

        int y = mid_y - (int)std::round(val * (float)mid_y / 1.5f);
        if (y < 0) y = 0;
        if (y >= height) y = height - 1;

        display[y][i] = (y == mid_y) ? 'o' : '*';
    }

    std::cout << "  [Step " << std::setw(3) << std::setfill('0') << sim->step
              << " | Heartbeat Amp: " << std::showpos << std::fixed << std::setprecision(4)
              << sim->source_amplitude << "]\n";
    std::cout << "  +----------------------------------------+\n";
    for (int i = 0; i < height; i++) {
        std::cout << "  |" << display[i] << "|\n";
    }
    std::cout << "  +----------------------------------------+\n";
}

